import{_ as s,c as a,o as i,b as d}from"./app.fab5ca80.js";const h='{"title":"\u0413\u043B\u0430\u0432\u0430 13","description":"","frontmatter":{"title":"\u0413\u043B\u0430\u0432\u0430 13","subtitle":"\u041C\u0430\u043B\u0438\u043D\u0438 \u0432\u0438\u0434\u0436\u0430\u0439\u043E\u0442\u0442\u0430\u0440\u0430 \u0442\u0430\u043D\u0442\u0440\u0430","tags":"malini","date":"2020-08-10T00:00:00.000Z"},"headers":[],"relativePath":"texts/malini-vijayottara/13.md"}',c={},n=d('<div class="stanza"><a href="#s13.1" id="s13.1" class="num">13.1</a><p>\u0422\u0435\u043F\u0435\u0440\u044C \u043F\u043E\u0432\u0435\u0434\u0430\u044E \u0412\u0430\u0440\u0443\u043D\u0438 \u0434\u0445\u0430\u0440\u0430\u043D\u0443. \u041F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u0443\u0441\u043F\u0435\u0445\u0430 \u0432 \u043D\u0435\u0439, (\u0439\u043E\u0433\u0438\u043D) \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F \u0432\u043B\u0430\u0434\u044B\u043A\u043E\u0439 \u0432\u043E\u0434 .</p></div><div class="stanza"><a href="#s13.2" id="s13.2" class="num">13.2</a><p>\u0421\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0442\u044C (\u0441\u0432\u043E\u0435) \u0442\u0435\u043B\u043E, \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044E\u0449\u0435\u0435 \u0441\u0440\u0435\u0434\u0438 \u0432\u043E\u0434\u044B, \u0431\u0435\u043B\u043E\u0435, \u043F\u0440\u043E\u0445\u043B\u0430\u0434\u043D\u043E\u0435, \u043A\u0440\u0443\u0433\u043B\u043E\u0435. \u041D\u0438\u0447\u0442\u043E \u0438\u043D\u043E\u0435 \u0432\u043D\u0443\u0442\u0440\u0438 \u0438 \u0441\u043D\u0430\u0440\u0443\u0436\u0438 \u0439\u043E\u0433\u0438\u043D \u043D\u0435 \u0434\u043E\u043B\u0436\u0435\u043D \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0442\u044C .</p></div><div class="stanza"><a href="#s13.3" id="s13.3" class="num">13.3</a><p>\u0411\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u044D\u0442\u043E\u0439 \u043F\u0440\u0430\u043A\u0442\u0438\u043A\u0435 \u043E\u043D \u0437\u0430 \u0441\u0435\u043C\u044C \u0434\u043D\u0435\u0439 \u043E\u043D \u043E\u0431\u0440\u0435\u0442\u0435\u0442 \u043C\u044F\u0433\u043A\u043E\u0441\u0442\u044C. \u0417\u0430 \u043C\u0435\u0441\u044F\u0446 \u043E\u043D \u043D\u0435\u043F\u0440\u0435\u043C\u0435\u043D\u043D\u043E \u0441\u0442\u0430\u043D\u0435\u0442 \u043F\u0440\u0435\u043E\u0434\u043E\u043B\u0435\u0432\u0448\u0438\u043C \u0431\u043E\u043B\u0435\u0437\u043D\u044C \u0436\u0435\u043B\u0447\u0438 (\u0436\u0435\u043B\u0442\u0443\u0445\u0443) .</p></div><div class="stanza"><a href="#s13.4" id="s13.4" class="num">13.4</a><p>\u0417\u0430 \u0433\u043E\u0434 \u0432\u043B\u0430\u0434\u044B\u043A\u0430 \u0439\u043E\u0433\u0438 \u043E\u0431\u0440\u0435\u0442\u0435\u0442 \u043D\u0435\u0436\u043D\u043E\u0435 \u0442\u0435\u043B\u043E, \u043D\u0435\u0436\u043D\u044B\u0439 \u0432\u0437\u0433\u043B\u044F\u0434, \u0440\u0430\u0437\u0432\u0435\u0432\u0430\u044E\u0449\u0443\u044E\u0441\u044F \u043D\u0430 \u0432\u0435\u0442\u0440\u0443 \u0448\u0435\u0432\u0435\u043B\u044E\u0440\u0443, \u0437\u0430 \u0442\u0440\u0438 \u0433\u043E\u0434\u0430 (\u0441\u0442\u0430\u043D\u0435\u0442) \u043F\u043E\u0434\u043E\u0431\u043D\u044B\u043C \u043E\u0431\u043B\u0430\u043A\u0443 .</p></div><div class="stanza"><a href="#s13.5" id="s13.5" class="num">13.5</a><p>\u042D\u0442\u043E \u0438\u043C\u0435\u043D\u0443\u0435\u0442\u0441\u044F \u043F\u0435\u0440\u0432\u043E\u0439, \u0447\u0438\u0441\u0442\u043E\u0439 \u0412\u0430\u0440\u0443\u043D\u0438 \u0434\u0445\u0430\u0440\u0430\u043D\u043E\u0439. \u0422\u0435\u043F\u0435\u0440\u044C \u0432\u043D\u043E\u0432\u044C \u043F\u043E\u0432\u0435\u0434\u0430\u044E \u043E \u0435\u0435 \u043F\u043E\u0434\u0440\u0430\u0437\u0434\u0435\u043B\u0435\u043D\u0438\u044F\u0445 .</p></div><div class="stanza"><a href="#s13.6" id="s13.6" class="num">13.6</a><p>\u0421\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0442\u044C, \u043A\u0430\u043A \u0438 \u0440\u0430\u043D\u044C\u0448\u0435, \u0441\u0432\u043E\u0435 \u0442\u0435\u043B\u043E \u0441\u043B\u0435\u0432\u0430 \u0438 \u0441\u043F\u0440\u0430\u0432\u0430, \u0431\u0435\u043B\u043E\u0435, \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044E\u0449\u0435\u0435 \u043D\u0430\u0434 \u0432\u043E\u0434\u043E\u0439, \u043E \u0414\u0435\u0432\u0438, \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044E\u0449\u0435\u0439 \u0432\u043D\u0443\u0442\u0440\u0438 (\u0439\u043E\u0433\u0438\u043D\u0430) .</p></div><div class="stanza"><a href="#s13.7" id="s13.7" class="num">13.7</a><p>\u0417\u0430 \u0441\u0435\u043C\u044C \u0434\u043D\u0435\u0439 (\u0439\u043E\u0433\u0438\u043D) \u043E\u0441\u0432\u043E\u0431\u043E\u0434\u0438\u0442\u0441\u044F \u043E\u0442 \u0432\u0441\u0435\u0445 \u0431\u043E\u043B\u0435\u0437\u043D\u0435\u0439, \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u044F\u0449\u0438\u0445 \u043E\u0442 \u0436\u0435\u043B\u0447\u0438. \u0417\u0430 \u0448\u0435\u0441\u0442\u044C \u043C\u0435\u0441\u044F\u0446\u0435\u0432 \u043F\u043E\u044F\u0432\u0438\u0442\u0441\u044F \u0443\u0441\u0442\u043E\u0439\u0447\u0438\u0432\u043E\u0441\u0442\u044C, \u0435\u0441\u043B\u0438 \u043E\u043D\u0438 \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u0435\u0442 \u0432 \u0435\u0434\u0438\u043D\u0441\u0442\u0432\u0435 \u0441 \u043D\u0435\u044E (\u0432\u043E\u0434\u043E\u0439) .</p></div><div class="stanza"><a href="#s13.8-9" id="s13.8-9" class="num">13.8-9</a><p>\u0417\u0430 \u0442\u0440\u0438 \u0433\u043E\u0434\u0430 \u043F\u043E\u044F\u0432\u0438\u0442\u0441\u044F \u0437\u043D\u0430\u043D\u0438\u0435 \u043E\u043A\u0440\u0443\u0436\u0435\u043D\u0438\u044F \u0432\u043E\u0434\u044B, \u043E\u043D \u043D\u0435 \u0431\u0443\u0434\u0435\u0442 \u0437\u0430\u0442\u0440\u043E\u043D\u0443\u0442 \u0440\u0430\u0437\u0434\u0435\u043B\u0435\u043D\u0438\u044F\u043C\u0438, \u043F\u043E\u0432\u0441\u044E\u0434\u0443 (\u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044F) \u043F\u043E\u0434\u043E\u0431\u043D\u043E \u0412\u0430\u0440\u0443\u043D\u0435 (\u0432\u043E\u0434\u0435). \u041E\u043D \u0434\u043E\u0441\u0442\u0438\u0433\u043D\u0435\u0442 \u0432\u0430\u0440\u0443\u043D\u0430 \u0442\u0430\u0442\u0442\u0432\u0443, \u0435\u0441\u043B\u0438 \u0431\u0443\u0434\u0435\u0442 \u043F\u0440\u0430\u043A\u0442\u0438\u043A\u043E\u0432\u0430\u0442\u044C \u043F\u043E\u0441\u0442\u0435\u043F\u0435\u043D\u043D\u043E (\u044D\u0442\u0438) \u0443\u0440\u043E\u0432\u043D\u0438. \u0421\u043B\u0435\u0434\u0443\u0435\u0442, \u043A\u0430\u043A \u043F\u0440\u0435\u0436\u0434\u0435, (\u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0442\u044C) \u0441\u0435\u0431\u044F, \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044E\u0449\u0435\u0433\u043E \u0432 \u0441\u0435\u0440\u0435\u0434\u0438\u043D\u0435 \u0433\u043E\u0440\u043B\u0430 (\u0440\u0430\u0437\u043C\u0435\u0440\u043E\u043C) 12 \u0430\u043D\u0433\u0443\u043B .</p></div><div class="stanza"><a href="#s13.10" id="s13.10" class="num">13.10</a><p>\u0421\u043E\u0437\u0435\u0440\u0446\u0430\u044E\u0449\u0438\u0439 \u0432\u043B\u0430\u0434\u044B\u043A\u0443 \u0442\u0430\u0442\u0442\u0432\u044B \u0432\u043E\u0434\u044B, \u043D\u0435\u043F\u0440\u0435\u043C\u0435\u043D\u043D\u043E \u0431\u044B\u0441\u0442\u0440\u043E \u0443\u0437\u0440\u0438\u0442 (\u0435\u0433\u043E). \u042D\u0442\u043E \u0432\u0438\u0434\u0435\u043D\u0438\u0435 \u0431\u0443\u0434\u0435\u0442 \u0443\u0441\u0442\u043E\u0439\u0447\u0438\u0432\u044B\u043C. \u0412 \u043F\u044F\u0442\u043E\u043C (\u0443\u0440\u043E\u0432\u043D\u0435 \u043D\u0430\u0441\u0442\u0443\u043F\u0438\u0442) \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u043D\u0438\u0435 \u0432 \u0441\u0432\u043E\u0435\u0439 \u0438\u0437\u043D\u0430\u0447\u0430\u043B\u044C\u043D\u043E\u0439 \u0444\u043E\u0440\u043C\u0435 .</p></div><div class="stanza"><a href="#s13.11" id="s13.11" class="num">13.11</a><p>\u0412\u043E \u0432\u0442\u043E\u0440\u043E\u043C \u043F\u043E\u0434\u0440\u0430\u0437\u0434\u0435\u043B\u0435\u043D\u0438\u0438, \u0441\u0442\u0430\u0432 \u0443\u0441\u0442\u043E\u0439\u0447\u0438\u0432\u044B\u043C, \u043D\u0430\u0434\u0435\u043B\u0435\u043D\u043D\u044B\u043C (\u0441\u0432\u0435\u0442\u043E\u043C) \u043B\u0443\u043D\u043D\u043E\u0433\u043E \u0434\u0438\u0441\u043A\u0430, \u043E\u043D \u0437\u0430\u0442\u0435\u043C \u0434\u043E\u0441\u0442\u0438\u0433\u043D\u0435\u0442 \u0435\u0434\u0438\u043D\u0441\u0442\u0432\u0430 \u0441 \u043D\u0438\u043C, \u0437\u0430\u0442\u0435\u043C (\u0435\u0434\u0438\u043D\u0441\u0442\u0432\u0430) \u0441 \u0444\u043E\u0440\u043C\u043E\u0439 \u0441\u0430\u043A\u0430\u043B\u044B .</p></div><div class="stanza"><a href="#s13.12" id="s13.12" class="num">13.12</a><p>\u0421\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0442\u044C \u043A\u0430\u043A \u0442\u0435\u043B\u043E \u043D\u0430\u043F\u043E\u043B\u043D\u044F\u0435\u0442\u0441\u044F \u0441\u0438\u044F\u043D\u0438\u0435\u043C, \u0431\u0435\u043B\u043E\u0433\u043E \u0446\u0432\u0435\u0442\u0430. \u0417\u0430\u0442\u0435\u043C \u043E\u043D\u043E \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F \u0443\u0441\u0442\u043E\u0439\u0447\u0438\u0432\u044B\u043C. \u0417\u0430\u0442\u0435\u043C \u043D\u0430\u0441\u0442\u0443\u043F\u0430\u0435\u0442 \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u043D\u0438\u0435 \u0432 \u0447\u0440\u0435\u0437\u0432\u044B\u0447\u0430\u0439\u043D\u043E\u0439 \u0443\u0441\u0442\u043E\u0439\u0447\u0438\u0432\u043E\u0441\u0442\u0438 .</p></div><div class="stanza"><a href="#s13.13" id="s13.13" class="num">13.13</a><p>\u0417\u0430\u0442\u0435\u043C \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0442\u044C \u0441\u0432\u0435\u0442 \u0433\u0440\u0443\u0434\u044B \u0436\u0435\u043C\u0447\u0443\u0433\u0430 \u0438 \u043B\u0443\u043D\u043D\u043E\u0433\u043E \u0434\u0438\u0441\u043A\u0430. \u041F\u0440\u0435\u043E\u0434\u043E\u043B\u0435\u0432 \u043D\u0435\u0443\u0441\u0442\u043E\u0439\u0447\u0438\u0432\u043E\u0441\u0442\u044C, \u0432\u0442\u043E\u0440\u044B\u043C \u043E\u043D \u043E\u0431\u0440\u0435\u0442\u0435\u0442 \u0443\u0441\u0442\u043E\u0439\u0447\u0438\u0432\u043E\u0441\u0442\u044C .</p></div><div class="stanza"><a href="#s13.14" id="s13.14" class="num">13.14</a><p>\u0417\u0430\u0442\u0435\u043C \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0442\u044C \u0431\u0435\u043B\u044B\u0439 \u0441\u0432\u0435\u0442 \u044D\u0442\u043E\u0433\u043E \u0441\u0438\u044F\u043D\u0438\u044F. (\u0411\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u044D\u0442\u043E\u043C\u0443, \u0439\u043E\u0433\u0438\u043D) \u043E\u0431\u0440\u0435\u0442\u0435\u0442 \u043F\u043E\u043B\u043E\u0436\u0435\u043D\u0438\u0435 \u0432\u0438\u0434\u0439\u0435\u0448\u0432\u0430\u0440\u044B, \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u044F\u0449\u0435\u0435 \u0438\u0437 \u043E\u043A\u0440\u0443\u0436\u0435\u043D\u0438\u044F \u0432\u043E\u0434\u044B .</p></div><div class="stanza"><a href="#s13.15" id="s13.15" class="num">13.15</a><p>\u0421\u043E\u0437\u0435\u0440\u0446\u0430\u044F \u0441\u0432\u043E\u0435 \u0442\u0435\u043B\u043E \u043D\u0430\u043F\u043E\u043B\u043D\u0435\u043D\u043D\u044B\u043C \u0438\u043C, \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044E\u0449\u0438\u043C \u0432 \u0431\u0435\u043B\u043E\u043C \u0441\u0432\u0435\u0442\u0435, (\u0439\u043E\u0433\u0438\u043D) \u043E\u0431\u0440\u0435\u0442\u0435\u0442 \u0432\u0441\u0435\u0432\u043B\u0430\u0441\u0442\u0438\u0435, \u0447\u0440\u0435\u0437\u0432\u044B\u0447\u0430\u0439\u043D\u043E \u0443\u0441\u0442\u043E\u0439\u0447\u0438\u0432\u043E \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044F \u0432 \u0447\u0440\u0435\u0437\u0432\u044B\u0447\u0430\u0439\u043D\u043E\u0439 \u0443\u0441\u0442\u043E\u0439\u0447\u0438\u0432\u043E\u0441\u0442\u0438 .</p></div><div class="stanza"><a href="#s13.16" id="s13.16" class="num">13.16</a><p>\u0415\u0434\u0438\u043D\u0441\u0442\u0432\u043E \u0441 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0435\u043C\u043E\u0439 \u0442\u0430\u0442\u0442\u0432\u043E\u0439 (\u043E\u0431\u0440\u0435\u0442\u0430\u0435\u0442\u0441\u044F) \u043D\u0430 \u0442\u0440\u0435\u0442\u044C\u0435\u043C \u0443\u0440\u043E\u0432\u043D\u0435. \u041D\u0430 \u0432\u0442\u043E\u0440\u043E\u043C \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442 \u043E\u0441\u043E\u0437\u043D\u0430\u043D\u0438\u0435 \u0435\u0435 \u0432\u043B\u0430\u0434\u044B\u043A\u0438 .</p></div><div class="stanza"><a href="#s13.17-18" id="s13.17-18" class="num">13.17-18</a><p>\u0418\u043B\u0438 \u0436\u0435 \u043D\u0430 \u0432\u0442\u043E\u0440\u043E\u043C (\u0443\u0440\u043E\u0432\u043D\u0435) \u0437\u043D\u0430\u044E\u0449\u0438\u0439 \u0439\u043E\u0433\u0443 \u0441\u0442\u0430\u043D\u0435\u0442 \u0443\u0441\u0442\u043E\u0439\u0447\u0438\u0432\u043E \u0435\u0434\u0438\u043D\u044B\u043C \u0441 \u043D\u0435\u0439. \u041D\u0430 \u0448\u0435\u0441\u0442\u043E\u043C \u043E\u043D \u043E\u0431\u0440\u0435\u0442\u0435\u0442 \u0432\u0441\u0435\u0432\u043B\u0430\u0434\u044B\u0447\u0435\u0441\u0442\u0432\u043E, \u043D\u043E \u0435\u0441\u043B\u0438 (\u0437\u0430\u0434\u0435\u0440\u0436\u0438\u0442\u0441\u044F) \u043D\u0430 \u0432\u0442\u043E\u0440\u043E\u043C, \u0442\u043E (\u043E\u0431\u0440\u0435\u0442\u0435\u0442) \u0433\u0438\u0431\u0435\u043B\u044C. \u0422\u0430\u043A\u043E\u0432\u044B \u0432\u0441\u0435 \u043F\u043E\u0434\u0440\u0430\u0437\u0434\u0435\u043B\u0435\u043D\u0438\u044F \u0442\u0430\u0442\u0442\u0432\u044B (\u0441\u043E\u0441\u0442\u0430\u0432\u043B\u044F\u044E\u0449\u0438\u0435) 15 \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u0435\u0439, \u0440\u0430\u0437\u043D\u043E\u043E\u0431\u0440\u0430\u0437\u043D\u043E \u043F\u043E\u0441\u0442\u0438\u0433\u0430\u0435\u043C\u044B\u0445, \u0437\u043D\u0430\u044E\u0449\u0438\u043C\u0438 \u043F\u0440\u0430\u0432\u0438\u043B\u0430, \u043D\u0430\u0434\u0435\u043B\u044F\u044E\u0449\u0438\u043C\u0438 \u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u0441\u0442\u0432\u0430\u043C\u0438 \u043F\u044F\u0442\u0438 \u043F\u043B\u043E\u0434\u043E\u0432 .</p></div><div class="stanza"><a href="#s13.19" id="s13.19" class="num">13.19</a><p>\u0411\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u044D\u0442\u043E\u043C\u0443 \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442 \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0438\u0439 \u043F\u043B\u043E\u0434 \u043E \u043A\u043E\u0442\u043E\u0440\u043E\u043C \u0433\u043E\u0432\u043E\u0440\u0438\u043B\u043E\u0441\u044C \u0438 (\u0441\u043D\u043E\u0432\u0430) \u0433\u043E\u0432\u043E\u0440\u0438\u0442\u0441\u044F. \u041F\u043E\u0437\u043D\u0430\u0432\u0430\u0435\u043C\u043E\u0435, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043F\u043B\u043E\u0434\u043E\u043C \u0435\u0434\u0438\u043D\u0441\u0442\u0432\u0430 \u0441 \u043D\u0435\u0439, \u0435\u0441\u0442\u044C \u0432\u0441\u0435, \u0431\u0435\u0437 \u0441\u043E\u043C\u043D\u0435\u043D\u0438\u044F .</p></div><div class="stanza"><a href="#s13.20" id="s13.20" class="num">13.20</a><p>\u042D\u0442\u0430 \u0438\u043C\u0435\u043D\u0443\u0435\u0442\u0441\u044F \u0432\u0430\u0440\u0443\u043D\u0438 (\u0434\u0445\u0430\u0440\u0430\u043D\u043E\u0439), \u043F\u043E\u0434\u0440\u0430\u0437\u0434\u0435\u043B\u044F\u0435\u043C\u043E\u0439 \u043D\u0430 \u043F\u044F\u0442\u043D\u0430\u0434\u0446\u0430\u0442\u044C. \u0420\u0430\u0434\u0438 \u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u0441\u0442\u0432\u0430 \u0439\u043E\u0433\u0438\u043D\u043E\u0432 \u0432 \u0439\u043E\u0433\u0435 \u0443\u0441\u043B\u044B\u0448\u044C \u043E\u0431 \u0430\u0433\u043D\u0435\u0438 (\u0434\u0445\u0430\u0440\u0430\u043D\u0435) .</p></div><div class="stanza"><a href="#s13.21" id="s13.21" class="num">13.21</a><p>\u0421\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0442\u044C \u0432 \u0442\u0435\u043B\u0435 \u0442\u0440\u0435\u0443\u0433\u0435\u043B\u044C\u043D\u0438\u043A, \u0441\u043E\u0434\u0435\u0440\u0436\u0430\u0449\u0438\u0439 \u043A\u0440\u0430\u0441\u043D\u043E\u0435 \u043F\u043B\u0430\u043C\u044F. (\u0431\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u044D\u0442\u043E\u043C\u0443) \u0437\u0430 \u0441\u0435\u043C\u044C \u0434\u043D\u0435\u0439, \u043E \u0414\u0435\u0432\u0438, (\u0443 \u0439\u043E\u0433\u0438\u043D\u0430) \u043F\u043E\u044F\u0432\u0438\u0442\u0441\u044F \u043E\u0441\u0442\u0440\u043E\u0442\u0430 .</p></div><div class="stanza"><a href="#s13.22" id="s13.22" class="num">13.22</a><p>\u0417\u0430 \u043C\u0435\u0441\u044F\u0446 \u0441\u0430\u0434\u0445\u0430\u043A\u0430 \u0438\u0437\u0431\u0430\u0432\u0438\u0442\u0441\u044F \u043E\u0442 \u0432\u0441\u0435\u0445 (\u0431\u043E\u043B\u0435\u0437\u043D\u0435\u0439), \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u044F\u0449\u0438\u0445 \u043E\u0442 \u0432\u0435\u0442\u0440\u0430 \u0438 \u0441\u043B\u0438\u0437\u0438. \u041E\u043D \u0441\u0442\u0430\u043D\u0435\u0442 \u043B\u0438\u0448\u0435\u043D\u043D\u044B\u043C \u0441\u043D\u0430, \u043C\u043D\u043E\u0433\u043E\u0435\u0434\u044F\u0449\u0438\u043C, \u043F\u0440\u043E\u0438\u0437\u0432\u043E\u0434\u044F\u0449\u0438\u043C \u043C\u043D\u043E\u0433\u043E \u043A\u0430\u043B\u0430 \u0438 \u043C\u043E\u0447\u0438 .</p></div><div class="stanza"><a href="#s13.23" id="s13.23" class="num">13.23</a><p>\u041F\u043E \u043F\u0440\u043E\u0448\u0435\u0441\u0442\u0432\u0438\u0438 \u0442\u0440\u0435\u0445 \u043C\u0435\u0441\u044F\u0446\u0435\u0432, \u043E\u043D \u043F\u043E \u0436\u0435\u043B\u0430\u043D\u0438\u044E \u0441\u043C\u043E\u0436\u0435\u0442 \u043F\u0435\u0440\u0435\u0432\u0430\u0440\u0438\u0442\u044C \u043B\u044E\u0431\u0443\u044E \u0432\u0435\u0449\u044C. \u0417\u0430 \u0442\u0440\u0438 \u0433\u043E\u0434\u0430, \u0441\u0442\u0430\u0432 \u0435\u0434\u0438\u043D\u044B\u043C \u0441 \u043E\u0433\u043D\u0435\u043C, \u043E\u043D \u0441\u043C\u043E\u0436\u0435\u0442 \u0438\u0433\u0440\u0430\u0442\u044C \u0441 \u043E\u0433\u043D\u0435\u043C .</p></div><div class="stanza"><a href="#s13.24" id="s13.24" class="num">13.24</a><p>\u0420\u0430\u0437\u0433\u043D\u0435\u0432\u0430\u043D\u043D\u044B\u0439, \u043E\u043D \u0441\u043C\u043E\u0436\u0435\u0442 \u0432\u0441\u0435 \u0441\u0436\u0435\u0447\u044C \u0432\u043C\u0435\u0441\u0442\u0435 \u0441 \u043B\u0435\u0441\u0430\u043C\u0438 \u0433\u043E\u0440\u0430\u043C\u0438 \u043F\u043E \u0436\u0435\u043B\u0430\u043D\u0438\u044E. \u0421\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0442\u044C \u0441\u0435\u0431\u044F, \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044E\u0449\u0435\u0433\u043E \u0432 \u0442\u0440\u0435\u0443\u0433\u043E\u043B\u044C\u043D\u043E\u0439 \u043C\u0430\u043D\u0434\u0430\u043B\u0435 .</p></div><div class="stanza"><a href="#s13.25" id="s13.25" class="num">13.25</a><p>\u0421\u0442\u0430\u0440\u0430\u0442\u0435\u043B\u044C\u043D\u043E, \u0441\u043B\u0435\u0432\u0430 \u0438 \u0441\u043F\u0440\u0430\u0432\u0430 \u0438 \u043F\u043E\u0432\u0441\u044E\u0434\u0443. \u0417\u0430 \u0441\u0435\u043C\u044C \u0434\u043D\u0435\u0439, (\u0439\u043E\u0433\u0438\u043D) \u0441\u0442\u0430\u043D\u0435\u0442 \u043B\u0438\u0448\u0435\u043D\u043D\u044B\u043C \u0431\u043E\u043B\u0435\u0437\u043D\u0435\u0439, \u0437\u0430 \u0448\u0435\u0441\u0442\u044C \u043C\u0435\u0441\u044F\u0446\u0435\u0432 \u0435\u0434\u0438\u043D\u044B\u043C \u0441 \u043E\u0433\u043D\u0435\u043C .</p></div><div class="stanza"><a href="#s13.26" id="s13.26" class="num">13.26</a><p>\u0417\u0430 \u0442\u0440\u0438 \u0433\u043E\u0434\u0430 \u043E\u043D \u043F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E \u0441\u043C\u043E\u0436\u0435\u0442 \u0432\u0438\u0434\u0435\u0442\u044C \u0442\u0430\u0442\u0442\u0432\u0443 \u043E\u0433\u043D\u044F. \u0412 \u0437\u0430\u0432\u0438\u0441\u0438\u043C\u043E\u0441\u0442\u0438 \u043E\u0442 \u0442\u043E\u0433\u043E, \u043A\u0430\u043A\u043E\u0432\u0430 \u0441\u043F\u043E\u0441\u043E\u0431\u043D\u043E\u0441\u0442\u044C (\u0448\u0430\u043A\u0442\u0438), \u043A\u0430\u043A\u043E\u0432\u043E \u0432\u0438\u0434\u0435\u043D\u0438\u0435, \u0432 \u0442\u0430\u043A\u043E\u043C \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u043D\u0438\u0438 \u043E\u043D \u0431\u0443\u0434\u0435\u0442 \u0443\u0441\u0442\u043E\u0439\u0447\u0438\u0432 .</p></div><div class="stanza"><a href="#s13.27" id="s13.27" class="num">13.27</a><p>\u0421\u043E\u0437\u0435\u0440\u0446\u0430\u044F \u0441\u0435\u0431\u044F \u043A\u0430\u043A \u043F\u0440\u0435\u0436\u0434\u0435 \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044E\u0449\u0438\u043C \u0432 \u043D\u0435\u0431\u0435, \u0446\u0432\u0435\u0442\u0430 \u043F\u043B\u0430\u043C\u0435\u043D\u0438, \u0443\u0432\u0438\u0434\u0438\u0442 \u043F\u043E \u043F\u043E\u0440\u044F\u0434\u043A\u0443 \u0432\u043B\u0430\u0434\u044B\u043A \u0442\u0430\u0442\u0442\u0432\u044B \u043E\u0433\u043D\u044F .</p></div><div class="stanza"><a href="#s13.28" id="s13.28" class="num">13.28</a><p>\u0421\u043E\u0437\u0435\u0440\u0446\u0430\u044E\u0449\u0438\u0439 \u0432 \u0446\u0435\u043D\u0442\u0440\u0435 \u043E\u0433\u043E\u043D\u044C, \u044F\u0432\u043B\u044F\u044E\u0449\u0438\u0439\u0441\u044F \u0432 \u043E\u043A\u0440\u0443\u0436\u0435\u043D\u0438\u0438 \u0434\u044B\u043C\u0430, \u043E\u0431\u043B\u0438\u043A\u043E\u043C \u043F\u043E\u0434\u043E\u0431\u043D\u044B\u0439 \u0441\u043E\u043B\u043D\u0435\u0447\u043D\u043E\u043C\u0443 \u0434\u0438\u0441\u043A\u0443, \u0441\u0442\u0430\u043D\u0435\u0442 \u0435\u0434\u0438\u043D\u044B\u043C \u0441 \u0432\u043B\u0430\u0434\u044B\u043A\u043E\u0439 \u0442\u0430\u0442\u0442\u0432\u044B \u043E\u0433\u043D\u044F .</p></div><div class="stanza"><a href="#s13.29" id="s13.29" class="num">13.29</a><p>\u0421\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0442\u044C <em>\u0441\u0430\u043A\u0430\u043B\u0443</em>, \u0441\u0432\u0435\u0442\u043E\u043C \u0443\u0441\u0442\u0440\u0430\u043D\u044F\u044E\u0449\u0435\u0433\u043E \u0441\u0435\u0442\u044C \u0442\u044C\u043C\u044B, \u0441\u0438\u044F\u044E\u0449\u0435\u0433\u043E \u043F\u043E\u0434\u043E\u0431\u043D\u043E \u043E\u0433\u043D\u044E \u0431\u0435\u0437 \u0434\u044B\u043C\u0430, (\u0442\u043E\u0433\u0434\u0430 \u0439\u043E\u0433\u0438\u043D) \u0434\u043E\u0441\u0442\u0438\u0433\u043D\u0435\u0442 \u0432\u043B\u0430\u0434\u044B\u0447\u0435\u0441\u0442\u0432\u0430 \u043D\u0430\u0434 \u043D\u0438\u043C .</p></div><div class="stanza"><a href="#s13.30" id="s13.30" class="num">13.30</a><p>\u0421\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0442\u044C \u043E\u0431\u0440\u0430\u0437 \u0434\u043D\u0435\u0432\u043D\u043E\u0433\u043E \u0441\u0432\u0435\u0442\u0430 \u0438 \u043E\u0433\u043D\u044F \u0430 \u0432 \u043D\u0435\u043C \u2013 \u043E\u0433\u043E\u043D\u044C. \u0422\u043E\u0433\u0434\u0430 \u043E\u043D \u043E\u0431\u0440\u0435\u0442\u0435\u0442 \u043F\u043E\u0434\u043E\u0431\u0438\u0435 \u0435\u043C\u0443. \u0412 \u043D\u0435\u043C \u043E\u043D \u043F\u0440\u0435\u0431\u0443\u0434\u0435\u0442 \u043D\u0435\u0434\u0432\u0438\u0436\u0438\u043C\u043E .</p></div><div class="stanza"><a href="#s13.31" id="s13.31" class="num">13.31</a><p>\u0422\u0430\u043C \u043E\u043D \u0434\u043E\u043B\u0436\u0435\u043D \u0441\u0438\u044F\u0442\u044C \u0431\u043B\u0435\u0441\u043A\u043E\u043C, \u043F\u043E\u0434\u043E\u0431\u043D\u043E \u0431\u043B\u0435\u0441\u043A\u0443 \u0434\u0440\u0430\u0433\u043E\u0446\u0435\u043D\u043D\u043E\u0441\u0442\u0435\u0439. \u041F\u0440\u0435\u0431\u044B\u0432\u0430\u044F \u0432 \u0435\u0434\u0438\u043D\u0441\u0442\u0432\u0435 \u0441 \u043D\u0438\u043C \u0439\u043E\u0433\u0438\u043D \u043E\u0431\u0440\u0435\u0442\u0435\u0442 \u043F\u043E\u043B\u043E\u0436\u0435\u043D\u0438\u0435 \u043C\u0430\u043D\u0442\u0440\u0435\u0448\u0438 .</p></div><div class="stanza"><a href="#s13.32" id="s13.32" class="num">13.32</a><p>\u0421\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0442\u044C \u0432\u043D\u0443\u0442\u0440\u0438 \u0438 \u0441\u043D\u0430\u0440\u0443\u0436\u0438, \u043E\u0433\u043E\u043D\u044C, \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044E\u0449\u0438\u0439 \u043F\u043E\u0432\u0441\u044E\u0434\u0443. \u0411\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u044D\u0442\u043E\u043C\u0443 (\u0439\u043E\u0433\u0438\u043D) \u043D\u0435 \u043F\u043E\u043A\u0438\u043D\u0435\u0442 \u044D\u0442\u043E \u043F\u043E\u043B\u043E\u0436\u0435\u043D\u0438\u0435, \u043D\u0435\u0443\u043D\u0438\u0447\u0442\u043E\u0436\u0438\u043C\u043E\u0435 \u0438 \u043D\u0435\u0434\u0435\u043B\u0438\u043C\u043E\u0435 .</p></div><div class="stanza"><a href="#s13.33" id="s13.33" class="num">13.33</a><p>\u041F\u0440\u0438 \u0433\u0438\u0431\u0435\u043B\u0438 (\u043C\u0438\u0440\u0430 \u043E\u043D \u0434\u043E\u0441\u0442\u0438\u0433\u043D\u0435\u0442) \u0432\u044B\u0441\u0448\u0435\u0433\u043E \u043F\u043E\u043B\u043E\u0436\u0435\u043D\u0438\u044F \u043F\u043E\u043A\u043E\u044F, (\u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u0435\u0441\u0442\u044C) \u0428\u0430\u043D\u043A\u0430\u0440\u0430. \u0422\u0430\u043A (\u0422\u0435\u0431\u0435) \u043D\u0430\u0437\u0432\u0430\u043D\u0430 \u043F\u044F\u0442\u043D\u0430\u0434\u0446\u0430\u0442\u0438\u0447\u0435\u0440\u0438\u0447\u043D\u0430\u044F \u0432\u0430\u0445\u043D\u0438 \u0434\u0445\u0430\u0440\u0430\u043D\u0430 .</p></div><div class="stanza"><a href="#s13.34" id="s13.34" class="num">13.34</a><p>\u0421\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0442\u044C \u0441\u0432\u043E\u0435 \u0442\u0435\u043B\u043E, \u0447\u0435\u0440\u043D\u043E\u0435 \u043F\u043E\u0434\u0432\u0438\u0436\u043D\u043E\u0435, \u043D\u0430\u0434\u0435\u043B\u0435\u043D\u043D\u043E\u0435 6 \u043D\u0430\u043F\u0440\u0430\u0432\u043B\u0435\u043D\u0438\u044F\u043C\u0438 (<em>\u0432\u043F\u0440\u0430\u0432\u043E, \u0432\u043B\u0435\u0432\u043E, \u0432\u043F\u0435\u0440\u0435\u0434, \u043D\u0430\u0437\u0430\u0434, \u0432\u0432\u0435\u0440\u0445, \u0432\u043D\u0438\u0437</em>) \u0438 5 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u044F\u043C\u0438 (<em>\u043F\u043E\u0434\u0431\u0440\u0430\u0441\u044B\u0432\u0430\u043D\u0438\u0435, \u043F\u0430\u0434\u0435\u043D\u0438\u0435, \u0441\u0436\u0430\u0442\u0438\u0435, \u0440\u0430\u0441\u0448\u0438\u0440\u0435\u043D\u0438\u0435, \u0434\u0432\u0438\u0436\u0435\u043D\u0438\u0435</em>), \u043F\u0440\u043E\u0445\u043B\u0430\u0434\u043D\u043E\u0435, \u0434\u0432\u0438\u0436\u0443\u0449\u0435\u0435\u0441\u044F \u0441\u043E \u0437\u0432\u0443\u043A\u043E\u043C \u0447\u0443-\u0447\u0443 (\u0432 \u044D\u0442\u043E\u043C \u0437\u0430\u043A\u043B\u044E\u0447\u0435\u043D\u0430) \u0432\u0430\u044F\u0432\u0438 \u0434\u0445\u0430\u0440\u0430\u043D\u0430 .</p></div><div class="stanza"><a href="#s13.35" id="s13.35" class="num">13.35</a><p>\u041F\u043E \u0443\u0441\u0442\u0440\u0430\u043D\u0435\u043D\u0438\u0438 \u0431\u043E\u043B\u0435\u0437\u043D\u0435\u0439, \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u044F\u0449\u0438\u0445 \u043E\u0442 \u043A\u0430\u043F\u0445\u0438, \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442 \u043F\u043E\u0434\u0432\u0438\u0436\u043D\u043E\u0441\u0442\u044C, \u043F\u043E\u0434\u043E\u0431\u043D\u0430\u044F \u0432\u0435\u0442\u0440\u0443. \u0417\u0430 \u0448\u0435\u0441\u0442\u044C \u043C\u0435\u0441\u044F\u0446\u0435\u0432 \u043F\u0440\u0430\u043A\u0442\u0438\u043A\u0438 \u0439\u043E\u0433\u0438\u043D, (\u0434\u043E\u0441\u0442\u0438\u0433\u043D\u0435\u0442) \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u043D\u0438\u044F \u0432 \u044D\u0442\u043E\u043C \u043F\u043E\u043B\u043E\u0436\u0435\u043D\u0438\u0438</p></div><div class="stanza"><a href="#s13.36" id="s13.36" class="num">13.36</a><p>\u0417\u0430 \u0447\u0430\u0441 (\u043C\u0443\u0445\u0443\u0440\u0442\u0443) \u0441\u043C\u043E\u0436\u0435\u0442 \u043F\u0440\u0435\u043E\u0434\u043E\u043B\u0435\u0442\u044C \u0441\u0442\u043E \u0439\u043E\u0434\u0436\u0430\u043D. \u0417\u0430 \u0442\u0440\u0438 \u0433\u043E\u0434\u0430 \u043E\u043D \u0441\u0442\u0430\u043D\u0435\u0442 \u043D\u0435\u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 \u0444\u043E\u0440\u043C\u043E\u0439 \u0432\u0435\u0442\u0440\u0430 .</p></div><div class="stanza"><a href="#s13.37" id="s13.37" class="num">13.37</a><p>\u041E\u043D \u0441\u043C\u043E\u0436\u0435\u0442 \u0432\u044B\u0432\u0435\u0442\u0440\u0438\u0432\u0430\u0442\u044C \u0433\u043E\u0440\u044B \u0438 \u0432\u044B\u043A\u043E\u0440\u0447\u0435\u0432\u044B\u0432\u0430\u0442\u044C \u0434\u0435\u0440\u0435\u0432\u044C\u044F. \u0420\u0430\u0437\u0433\u043D\u0435\u0432\u0430\u043D\u043D\u044B\u0439, \u043E\u043D \u0431\u0443\u0434\u0435\u0442 \u043F\u043E\u0432\u0435\u043B\u0435\u0432\u0430\u0442\u044C \u0428\u0430\u043A\u0440\u043E\u0439 (\u0418\u043D\u0434\u0440\u043E\u0439), \u0438 \u0442\u043E\u0442, \u043B\u0438\u0448\u0435\u043D\u043D\u044B\u0439 \u0441\u0438\u043B, \u0431\u0443\u0434\u0435\u0442 \u043F\u0440\u0438\u0441\u043B\u0443\u0436\u0438\u0432\u0430\u0442\u044C \u0435\u043C\u0443 .</p></div><div class="stanza"><a href="#s13.38" id="s13.38" class="num">13.38</a><p>\u0421\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0442\u044C \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0435 \u0442\u0435\u043B\u043E \u0433\u043E\u043B\u0443\u0431\u043E\u0433\u043E \u0446\u0432\u0435\u0442\u0430. \u0417\u0430 \u0448\u0435\u0441\u0442\u044C \u043C\u0435\u0441\u044F\u0446\u0435\u0432 (\u0439\u043E\u0433\u0438\u043D) \u0434\u043E\u0441\u0442\u0438\u0433\u043D\u0435\u0442 \u0432\u0441\u0435\u0433\u043E, \u043A\u0430\u043A \u0431\u044B\u043B\u043E \u0441\u043A\u0430\u0437\u0430\u043D\u043E \u0440\u0430\u043D\u044C\u0448\u0435, \u0431\u0435\u0437 \u0441\u043E\u043C\u043D\u0435\u043D\u0438\u044F .</p></div><div class="stanza"><a href="#s13.39" id="s13.39" class="num">13.39</a><p>\u0417\u0430 \u0442\u0440\u0438 \u0433\u043E\u0434\u0430 \u043E\u043D \u0443\u0437\u0440\u0438\u0442 \u0432\u0430\u044E \u0442\u0430\u0442\u0442\u0432\u0443, \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044F \u0432 \u0435\u0434\u0438\u043D\u0441\u0442\u0432\u0435 \u0441 \u043D\u0435\u0439. \u0412 \u043C\u0435\u0436\u0431\u0440\u043E\u0432\u0438\u0438 \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0442\u044C \u0444\u043E\u0440\u043C\u0443 \u0410\u0442\u043C\u0430\u043D\u0430 (\u0441\u0435\u0431\u044F) \u0446\u0432\u0435\u0442\u0430 \u0442\u0443\u0448\u0438 .</p></div><div class="stanza"><a href="#s13.40" id="s13.40" class="num">13.40</a><p>(\u0422\u043E\u0433\u0434\u0430 \u0439\u043E\u0433\u0438\u043D) \u0443\u0437\u0440\u0438\u0442 \u0432\u0441\u0435\u0445 \u0447\u0438\u0441\u0442\u044B\u0445 \u0432\u043B\u0430\u0434\u044B\u043A \u0432\u0430\u044E \u0442\u0430\u0442\u0442\u0432\u044B, \u0434\u0435\u0439\u0441\u0442\u0432\u0443\u044E\u0449\u0438\u0445 \u0432 \u0441\u043E\u0432\u043E\u043A\u0443\u043F\u043D\u043E\u0441\u0442\u0438 \u0447\u0443\u0432\u0441\u0442\u0432, \u0446\u0432\u0435\u0442\u0430 \u043D\u0435\u0431\u0430, \u043E\u0431\u043B\u0438\u043A\u043E\u043C \u043F\u043E\u0434\u043E\u0431\u043D\u044B\u0445 \u0441\u043E\u043B\u043D\u0435\u0447\u043D\u043E\u043C\u0443 \u0434\u0438\u0441\u043A\u0443 .</p></div><div class="stanza"><a href="#s13.41" id="s13.41" class="num">13.41</a><p>\u0421\u043E\u0437\u0435\u0440\u0446\u0430\u044E\u0449\u0438\u0439 \u0435\u0435, \u0434\u043E\u0441\u0442\u0438\u0433\u0430\u0435\u0442 \u0435\u0434\u0438\u043D\u0441\u0442\u0432\u0430 \u0441 \u043D\u0435\u0439. \u041A\u043E\u0433\u0434\u0430 \u044D\u0442\u043E \u043F\u0440\u043E\u0438\u0437\u043E\u0439\u0434\u0435\u0442, \u043E\u043D \u043F\u043E\u0433\u0440\u0443\u0437\u0438\u0442\u0441\u044F \u0432 \u043D\u0435\u0435. \u0422\u0430\u043C \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0442\u044C \u0441\u0430\u043A\u0430\u043B\u0443, \u044F\u0432\u043B\u044F\u044E\u0449\u0443\u044E\u0441\u044F \u043A\u0430\u043A \u043D\u0435\u0431\u043E, \u0440\u0430\u0437\u0431\u0438\u0442\u043E\u0435 \u0418\u043D\u0434\u0440\u043E\u0439 (\u043C\u043E\u043B\u043D\u0438\u0435\u0439) .</p></div><div class="stanza"><a href="#s13.42" id="s13.42" class="num">13.42</a><p>\u041E\u043D \u0434\u043E\u0441\u0442\u0438\u0433\u043D\u0435\u0442 \u043F\u0440\u0438\u0440\u043E\u0434\u044B \u043C\u0430\u043D\u0442\u0440\u0435\u0448\u0438, \u0437\u0430\u0442\u0435\u043C \u0432\u043B\u0430\u0434\u044B\u0447\u0435\u0441\u0442\u0432\u0430 \u043D\u0430\u0434 \u043D\u0435\u0439. \u041F\u0440\u0438 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u043D\u0438\u0438 \u0435\u0433\u043E \u0432\u0441\u0435\u043F\u0440\u043E\u043D\u0438\u043A\u0430\u044E\u0449\u0435\u0439 \u0432\u0430\u0440\u043D\u044B, \u043E\u043D \u0434\u043E\u0441\u0442\u0438\u0433\u043D\u0435\u0442 \u0435\u0435 \u043C\u043E\u0433\u0443\u0449\u0435\u0441\u0442\u0432\u0430 .</p></div><div class="stanza"><a href="#s13.43" id="s13.43" class="num">13.43</a><p>\u0417\u0430\u0442\u0435\u043C \u043E\u043D \u0434\u043E\u0441\u0442\u0438\u0433\u0430\u0435\u0442 \u041F\u0440\u0435\u0432\u043E\u0441\u0445\u043E\u0434\u0441\u0442\u0432\u0430 \u043D\u0430\u0434 \u043D\u0435\u0439, \u0441\u043A\u043E\u043B\u044C\u0437\u044F\u0449\u0435\u0439 \u0432\u0432\u0435\u0440\u0445 \u0438 \u0432\u043D\u0438\u0437. \u0422\u0430\u043A\u043E\u0432\u0430 \u043F\u043E\u0432\u0435\u0434\u0430\u043D\u043D\u0430\u044F \u0431\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u0430\u044F \u0432\u0430\u044E \u0434\u0445\u0430\u0440\u0430\u043D\u0430 .</p></div><div class="stanza"><a href="#s13.44" id="s13.44" class="num">13.44</a><p>\u0421\u043E\u0437\u0435\u0440\u0446\u0430\u044F \u0441\u0432\u043E\u0435 \u0442\u0435\u043B\u043E, \u043F\u043E\u0434\u043E\u0431\u043D\u043E\u0435 \u0432\u0435\u0442\u0440\u0443 \u0438 \u0435\u0433\u043E \u043E\u0442\u0441\u0443\u0442\u0441\u0442\u0432\u0438\u0435, \u0439\u043E\u0433\u0438\u043D \u0437\u0430 \u0441\u0435\u043C\u044C \u0434\u043D\u0435\u0439 \u0434\u043E\u0441\u0442\u0438\u0433\u043D\u0435\u0442 \u043F\u0443\u0441\u0442\u043E\u0442\u043D\u043E\u0441\u0442\u0438 .</p></div><div class="stanza"><a href="#s13.45" id="s13.45" class="num">13.45</a><p>\u0417\u0430 \u043C\u0435\u0441\u044F\u0446, \u0434\u0430\u0436\u0435 \u0430\u0442\u0430\u043A\u043E\u0432\u0430\u043D\u043D\u044B\u0439 \u0432\u043B\u0430\u0434\u044B\u043A\u0430\u043C\u0438 \u043D\u0430\u0441\u043B\u0430\u0436\u0434\u0435\u043D\u0438\u0439, \u043E\u043D \u043D\u0435 \u0441\u043C\u0443\u0442\u0438\u0442\u0441\u044F, \u043E\u0441\u0442\u0430\u0432\u0438\u0432 \u0431\u043E\u043B\u0435\u0437\u043D\u0438, \u0441\u0432\u043E\u0431\u043E\u0434\u043D\u044B\u0439 \u043E\u0442 \u043B\u0438\u0445\u043E\u0440\u0430\u0434\u043A\u0438 .</p></div><div class="stanza"><a href="#s13.46" id="s13.46" class="num">13.46</a><p>\u0417\u0430 \u0448\u0435\u0441\u0442\u044C \u043C\u0435\u0441\u044F\u0446\u0435\u0432 \u043E\u043D \u0441\u043C\u043E\u0436\u0435\u0442 \u043F\u0440\u043E\u0445\u043E\u0434\u0438\u0442 \u0441\u043A\u0432\u043E\u0437\u044C \u0443\u0437\u043A\u0438\u0435 \u043E\u0442\u0432\u0435\u0440\u0441\u0442\u0438\u044F, \u043F\u043E\u0434\u043E\u0431\u043D\u043E \u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0441\u0442\u0432\u0443. \u0417\u0430 \u0442\u0440\u0438 \u0441 \u043F\u043E\u043B\u043E\u0432\u0438\u043D\u043E\u0439 \u0433\u043E\u0434\u0430 \u043E\u043D \u0441\u0442\u0430\u043D\u0435\u0442 \u043F\u043E\u0434\u043E\u0431\u043D\u044B\u043C \u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0441\u0442\u0432\u0443 .</p></div><div class="stanza"><a href="#s13.47" id="s13.47" class="num">13.47</a><p>\u041F\u043E \u0436\u0435\u043B\u0430\u043D\u0438\u044E (\u043E\u043D \u0441\u043C\u043E\u0436\u0435\u0442 \u043F\u0440\u0438\u043D\u0438\u043C\u0430\u0442\u044C) \u043E\u0433\u0440\u043E\u043C\u043D\u043E\u0435 \u0442\u0435\u043B\u043E, \u043F\u043E \u0436\u0435\u043B\u0430\u043D\u0438\u044E \u2013 \u043C\u0430\u043B\u043E\u0435, \u043A\u0440\u0435\u043F\u043A\u043E\u0435, (\u043D\u0435\u0434\u0435\u043B\u0438\u043C\u043E\u0435) \u043D\u0435\u0440\u0443\u0448\u0438\u043C\u043E\u0435. \u041E\u043D \u0443\u0437\u0440\u0438\u0442 \u041C\u0435\u0434\u0438\u043D\u0438;</p></div><div class="stanza"><a href="#s13.48" id="s13.48" class="num">13.48</a><p>(\u0410\u0440\u043E\u043C\u0430\u0442\u043E\u043C) \u043F\u043E\u0434\u043E\u0431\u043D\u0443\u044E \u043D\u0435\u043A\u0442\u0430\u0440\u0443 \u0441\u043E\u0442\u0435\u043D \u043F\u0440\u0435\u0434\u043B\u043E\u0436\u0435\u043D\u043D\u044B\u0445 \u0446\u0432\u0435\u0442\u043E\u0432, (\u0446\u0432\u0435\u0442\u043E\u043C) \u043F\u043E\u0434\u043E\u0431\u043D\u0443\u044E \u043C\u0438\u043B\u043B\u0438\u0430\u0440\u0434\u0443 \u0443\u0442\u0440\u043E\u0431 \u0437\u0430\u0440\u0438. \u0421\u043E\u0437\u0435\u0440\u0446\u0430\u044F (\u0442\u0430\u043A) \u0442\u0435\u043B\u043E, \u0437\u0430 \u0442\u0440\u0438 \u0433\u043E\u0434\u0430 \u0443 \u043D\u0435\u0433\u043E \u043F\u043E\u044F\u0432\u0438\u0442\u0441\u044F \u0437\u043D\u0430\u043D\u0438\u0435 \u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0441\u0442\u0432\u0430 .</p></div><div class="stanza"><a href="#s13.49" id="s13.49" class="num">13.49</a><p>\u041E\u043F\u0438\u0441\u0430\u043D\u043D\u044B\u0439 \u0432\u044B\u0448\u0435 \u043F\u043B\u043E\u0434 \u043E\u043D \u043E\u0431\u0440\u0435\u0442\u0435\u0442 \u0437\u0430 \u0441\u0435\u043C\u044C \u0434\u043D\u0435\u0439. \u0412\u043E \u043B\u0431\u0443 \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0442\u044C \u0421\u0435\u0431\u044F \u0440\u0430\u0437\u043C\u0435\u0440\u043E\u043C 12 \u0430\u043D\u0433\u0443\u043B,</p></div><div class="stanza"><a href="#s13.50" id="s13.50" class="num">13.50</a><p>\u041E\u043D \u0443\u0437\u0440\u0438\u0442 \u043F\u043E \u043F\u043E\u0440\u044F\u0434\u043A\u0443 \u0432\u0441\u0435\u0445 \u0432\u043B\u0430\u0434\u044B\u043A \u044D\u0442\u043E\u0439 \u0442\u0430\u0442\u0442\u0432\u044B, \u0441\u0442\u043E\u044F\u0449\u0438\u0445 \u0432\u043F\u0435\u0440\u0435\u0434\u0438 (\u043D\u0435\u0433\u043E). \u0421\u043E\u0437\u0435\u0440\u0446\u0430\u044F (\u0441\u0435\u0431\u044F) \u0446\u0432\u0435\u0442\u0430 \u043B\u0443\u043D\u043D\u043E\u0433\u043E \u0434\u0438\u0441\u043A\u0430, \u0437\u0430\u043A\u0440\u044B\u0442\u043E\u0433\u043E \u0420\u0430\u0445\u0443, \u043E\u043D \u0441\u0442\u0430\u043D\u0435\u0442 \u0435\u0434\u0438\u043D\u044B\u043C \u0441 \u043D\u0435\u0439 .</p></div><div class="stanza"><a href="#s13.51" id="s13.51" class="num">13.51</a><p>\u0421\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0442\u044C \u0441\u0430\u043A\u0430\u043B\u0443, \u0432 \u0432\u0438\u0434\u0435 \u043B\u0443\u043D\u043D\u043E\u0433\u043E \u0434\u0438\u0441\u043A\u0430, \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044E\u0449\u0443\u044E \u0442\u0430\u043C. \u0411\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u044D\u0442\u043E\u043C\u0443 \u043B\u0443\u043D\u043D\u043E\u043C\u0443 \u0441\u0432\u0435\u0442\u0443 \u043E\u043D \u043E\u0431\u0440\u0435\u0442\u0435\u0442 \u043F\u0440\u0438\u0440\u043E\u0434\u0443 \u043C\u0430\u043D\u0442\u0440\u0435\u0448\u0438 .</p></div><div class="stanza"><a href="#s13.52" id="s13.52" class="num">13.52</a><p>\u0411\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u044D\u0442\u043E\u043C\u0443, \u0441\u043A\u043E\u043B\u044C\u0437\u044F \u0432\u043D\u0438\u0437, \u0432\u043D\u0443\u0442\u0440\u0438 \u0438 \u0441\u043D\u0430\u0440\u0443\u0436\u0438, \u043C\u0443\u0434\u0440\u044B\u0439, \u0434\u043E\u0441\u0442\u0438\u0433\u043D\u0443\u0432 \u043F\u0440\u0438\u0440\u043E\u0434\u044B \u043C\u0430\u043D\u0442\u0440\u0435\u0448\u0438, \u0434\u043E\u0441\u0442\u0438\u0433\u0430\u0435\u0442 \u043D\u0435\u0441\u0440\u0430\u0432\u043D\u0435\u043D\u043D\u043E\u0433\u043E \u0437\u043D\u0430\u043D\u0438\u044F .</p></div><div class="stanza"><a href="#s13.53" id="s13.53" class="num">13.53</a><p>\u0411\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u0435\u043C\u0443, \u0441\u043A\u043E\u043B\u044C\u0437\u044F\u0449\u0435\u043C\u0443 \u0432\u0432\u0435\u0440\u0445, \u0447\u0435\u0440\u0435\u0437 \u0441\u0432\u0435\u0442 \u0432 \u0444\u043E\u0440\u043C\u0435 \u0430\u043C\u0440\u0438\u0442\u044B \u0438 \u0434\u043E\u0441\u0442\u0438\u0433\u043D\u0443\u0432\u0448\u0435\u043C\u0443 \u0441\u0432\u043E\u0431\u043E\u0434\u044B, \u0435\u043C\u0443 \u043D\u0438\u043A\u0442\u043E \u043D\u0435 \u0441\u043C\u043E\u0436\u0435\u0442 \u043F\u0440\u043E\u0442\u0438\u0432\u043E\u0441\u0442\u043E\u044F\u0442\u044C .</p></div><div class="stanza"><a href="#s13.54" id="s13.54" class="num">13.54</a><p>\u0418\u0442\u0430\u043A \u043D\u0430\u0437\u0432\u0430\u043D\u043D\u0430\u044F \u0434\u0445\u0430\u0440\u0430\u043D\u0430 \u043F\u044F\u0442\u0438 \u0442\u0430\u0442\u0442\u0432 \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044E\u0449\u0430\u044F \u0432 \u0447\u0438\u0441\u0442\u044B\u0445 \u0430\u0434\u0445\u0430\u0432\u0430\u0445, \u043F\u044F\u0442\u0438\u0440\u0438\u0447\u043D\u043E \u043E\u0445\u0432\u0430\u0442\u044B\u0432\u0430\u0435\u0442 \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u0435 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0430 .</p></div><div class="stanza"><a href="#s13.55" id="s13.55" class="num">13.55</a><p>\u0412 \u043D\u0438\u0445 \u043F\u043E\u043C\u0435\u0449\u0430\u0435\u0442\u0441\u044F \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u0435, \u044F\u0432\u043B\u044F\u044E\u0449\u0435\u0435\u0441\u044F \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u044C\u044E \u0440\u0430\u0441\u0442\u0432\u043E\u0440\u0435\u043D\u0438\u044F \u0432\u0438\u0448\u0438 \u0438 \u043F\u0440\u043E\u0447\u0435\u0433\u043E \u043E\u0442\u043B\u0438\u0447\u043D\u043E\u0433\u043E \u043E\u0442 \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442 \u043F\u043E \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 \u0412\u043E\u043B\u0435 .</p></div><div class="stanza"><a href="#s13.56" id="s13.56" class="num">13.56</a><p>\u0421\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u0434\u0435\u043B\u0430\u0442\u044C \u043E\u0441\u043E\u0437\u043D\u0430\u043D\u0438\u0435 \u0443\u0441\u0442\u043E\u0439\u0447\u0438\u0432\u044B\u043C, \u044D\u0442\u0438\u043C \u043E\u0431\u0440\u0435\u0442\u0430\u0435\u0442\u0441\u044F \u0435\u0433\u043E \u043F\u043B\u043E\u0434. \u041E\u043D\u043E \u0434\u043E\u043B\u0436\u043D\u043E \u0441\u0442\u0430\u0442\u044C \u0435\u0434\u0438\u043D\u044B\u043C, \u043D\u0435 \u043F\u043E\u0434\u0432\u0435\u0440\u0436\u0435\u043D\u043D\u044B\u043C \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0435\u043C\u0443 \u0440\u0430\u0437\u0434\u0435\u043B\u0435\u043D\u0438\u044E .</p></div><div class="stanza"><a href="#s13.57" id="s13.57" class="num">13.57</a><p>\u041A\u0442\u043E \u0434\u043E\u0441\u0442\u0438\u0433\u0430\u0435\u0442 \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u043D\u0438\u0435 \u0432\u043D\u0443\u0442\u0440\u0438, \u043D\u0435 \u0434\u043E\u043B\u0436\u0435\u043D \u043E\u0441\u0442\u0430\u043D\u0430\u0432\u043B\u0438\u0432\u0430\u0442\u044C\u0441\u044F, \u0441\u043E\u0432\u0435\u0440\u0448\u0430\u044E\u0449\u0438\u0439 \u043E\u0441\u0442\u0430\u043D\u043E\u0432\u043A\u0443, \u043D\u0435 \u0434\u043E\u0441\u0442\u0438\u0433\u043D\u0435\u0442 \u0432\u044B\u0441\u0448\u0435\u0433\u043E \u043F\u043B\u043E\u0434\u0430 .</p></div><div class="stanza"><a href="#s13.58" id="s13.58" class="num">13.58</a><p>\u041F\u0440\u0438 \u043E\u0431\u0440\u0435\u0442\u0435\u043D\u0438\u0438 \u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u0441\u0442\u0432 \u043F\u044F\u0442\u0438 \u0434\u0445\u0430\u0440\u0430\u043D \u0439\u043E\u0433\u0438\u043D\u044B \u043E\u0431\u0440\u0435\u0442\u0430\u044E\u0442 11 \u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u0441\u0442\u0432 \u043F\u0438\u0448\u0430\u0447\u0435\u0439, \u0438 \u043F\u044F\u0442\u044C \u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u0441\u0442\u0432 \u0418\u043D\u0434\u0440\u044B. \u0422\u0430\u043A \u043F\u043E\u0434\u0440\u0430\u0437\u0434\u0435\u043B\u044F\u044E\u0442\u0441\u044F \u0439\u043E\u0433\u0438\u043D\u044B .</p></div><div class="stanza"><a href="#s13.59" id="s13.59" class="num">13.59</a><p>\u041F\u0440\u0430\u043A\u0442\u0438\u043A\u0443\u044F \u043F\u043E \u043F\u043E\u0440\u044F\u0434\u043A\u0443 \u0432 \u043F\u044F\u0442\u043D\u0430\u0434\u0446\u0430\u0442\u0438 \u0443\u0440\u043E\u0432\u043D\u044F\u0445 \u0436\u0435\u043B\u0430\u043D\u043D\u044B\u0435 (\u0441\u0438\u0434\u0434\u0445\u0438) \u043E\u0431\u0440\u0435\u0442\u0430\u044E\u0442\u0441\u044F \u0437\u0430 \u0442\u0440\u0438 \u0433\u043E\u0434\u0430 \u043E\u0442 \u043D\u0430\u0447\u0430\u043B\u0430 (\u043F\u0440\u0430\u043A\u0442\u0438\u043A\u0438), \u0430 \u043D\u0435\u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u0437\u0430 \u0434\u0432\u0430 \u0438 \u043E\u0434\u0438\u043D (\u0433\u043E\u0434) .</p></div><div class="stanza"><a href="#s13.60" id="s13.60" class="num">13.60</a><p>\u0418\u043D\u044B\u0435 \u0437\u0430 \u0448\u0435\u0441\u0442\u044C \u043C\u0435\u0441\u044F\u0446\u0435\u0432 \u0438 \u043F\u044F\u0442\u044C \u043C\u0435\u0441\u044F\u0446\u0435\u0432, \u0447\u0435\u0442\u044B\u0440\u0435 \u0438 \u0442\u0440\u0438, \u0434\u0432\u0430 \u0438 \u043E\u0434\u0438\u043D, \u0437\u0430 (\u043E\u0434\u043D\u0443) \u043F\u0430\u043A\u0448\u0443, \u0437\u0430 \u043F\u044F\u0442\u043D\u0430\u0434\u0446\u0430\u0442\u044C \u0438 \u0434\u0435\u0441\u044F\u0442\u044C \u0434\u043D\u0435\u0439;</p></div><div class="stanza"><a href="#s13.61" id="s13.61" class="num">13.61</a><p>\u0422\u0440\u0438, \u0434\u0432\u0430 \u0438\u043B\u0438 \u043E\u0434\u0438\u043D, \u0441\u043E\u0433\u043B\u0430\u0441\u043D\u043E \u043C\u043D\u043E\u0436\u0435\u0441\u0442\u0432\u0443 \u0436\u0435\u043B\u0430\u043D\u0438\u0439 \u043A\u0430\u043A \u0431\u044B\u043B\u043E \u043E\u043F\u0438\u0441\u0430\u043D\u043E \u0432\u044B\u0448\u0435. (\u0419\u043E\u0433\u0438\u043D), \u043D\u0430\u0441\u043B\u0430\u0434\u0438\u0432\u0448\u0438\u0441\u044C \u0436\u0435\u043B\u0430\u043D\u043D\u044B\u043C\u0438 \u0441\u0438\u0434\u0434\u0445\u0438, \u043E\u0431\u0440\u0435\u0442\u0435\u0442 \u0432\u0435\u0447\u043D\u043E\u0435 \u043F\u043E\u043B\u043E\u0436\u0435\u043D\u0438\u0435 .</p></div><p>\u0422\u0430\u043A\u043E\u0432\u0430 \u0432 \u0441\u0432\u044F\u0449\u0435\u043D\u043D\u043E\u0439 \xAB\u041C\u0430\u043B\u0438\u043D\u0438 \u0432\u0438\u0434\u0436\u0430\u0439\u043E\u0442\u0442\u0430\u0440\u0430 \u0442\u0430\u043D\u0442\u0440\u0435\xBB \u0442\u0440\u0438\u043D\u0430\u0434\u0446\u0430\u0442\u0430\u044F \u0433\u043B\u0430\u0432\u0430</p>',60),l=[n];function p(v,t,e,r,m,f){return i(),a("div",null,l)}var z=s(c,[["render",p]]);export{h as __pageData,z as default};
